import React, { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../../utils/firebase'; // Ensure this matches your actual firebase config path
import { doc, getDoc, updateDoc, arrayUnion } from 'firebase/firestore';
import { Camera, RefreshCw, AlertTriangle, CheckCircle2 } from 'lucide-react';

export default function MaterialWorker() {
  // State Management
  const [parentId, setParentId] = useState('platform no 1'); // Hardcoded based on your node initialization layout
  const [quantity, setQuantity] = useState(1);
  const [isProcessing, setIsProcessing] = useState(false);
  const [errorAlert, setErrorAlert] = useState(null);
  const [successAlert, setSuccessAlert] = useState(null);
  
  // Camera & Stream States
  const videoRef = useRef(null);
  const streamRef = useRef(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [capturedBlob, setCapturedBlob] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);

  // 1. Initialize and Start Camera Safely (Prevents AbortError)
  const startCamera = async () => {
    setErrorAlert(null);
    try {
      if (streamRef.current) {
        stopCamera();
      }

      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment', width: 640, height: 480 }
      });
      
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        
        // Fix for: "AbortError: The play() request was interrupted"
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          playPromise
            .then(() => {
              setCameraActive(true);
            })
            .catch((err) => {
              if (err.name === 'AbortError') {
                console.warn("Camera play initialization safely intercepted during re-render.");
              } else {
                setErrorAlert(`Camera display failed: ${err.message}`);
              }
            });
        }
      }
    } catch (err) {
      console.error("Camera access error:", err);
      setErrorAlert("Could not access webcam device. Please check permissions.");
    }
  };

  // Stop media tracks safely
  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.srcObject = null;
    }
    setCameraActive(false);
  };

  // Trigger camera on mount
  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  // 2. Capture Frame from Video Stream
  const captureFrame = () => {
    if (!videoRef.current || !cameraActive) return;

    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth || 640;
    canvas.height = videoRef.current.videoHeight || 480;
    const ctx = canvas.getContext('2d');
    
    ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
    
    canvas.toBlob((blob) => {
      if (blob) {
        setCapturedBlob(blob);
        const url = URL.createObjectURL(blob);
        setPreviewUrl(url);
        stopCamera(); // Pause stream once captured
      }
    }, 'image/jpeg', 0.85);
  };

  const handleRetake = () => {
    setCapturedBlob(null);
    setPreviewUrl(null);
    startCamera();
  };

  // 3. Process Matrix Audit Changes & Firestore Registry Safety Verification
  const handleProcessMatrixAudit = async (e) => {
    e.preventDefault();
    setIsProcessing(true);
    setErrorAlert(null);
    setSuccessAlert(null);

    // Defensive check for the ID mapping structure
    if (!parentId || parentId.trim() === "") {
      setErrorAlert("Parent registry identifier cannot be empty.");
      setIsProcessing(false);
      return;
    }

    try {
      // Direct Firestore root check validation matching your alert path schema
      // Sanitizes trailing/leading spaces which commonly cause mismatches on "platform no 1 "
      const cleanRegistryKey = parentId.trim();
      const registryDocRef = doc(db, "registry", cleanRegistryKey);
      const registrySnap = await getDoc(registryDocRef);

      if (!registrySnap.exists()) {
        // Explicit structural alert reflecting your system requirement
        const targetErrorMessage = "Parent registry code reference broken inside Firestore root.";
        setErrorAlert(targetErrorMessage);
        alert(targetErrorMessage); // Browser native block matching design layout
        setIsProcessing(false);
        return;
      }

      // Mock processing upload/save behavior for the matrix payload
      // In production, replace this string with your Firebase Storage upload downloadURL link
      const simulatedPhotoUrl = previewUrl || "https://placeholder.via.placeholder.com/640";

      await updateDoc(registryDocRef, {
        auditLogs: arrayUnion({
          quantity: Number(quantity),
          verificationPhoto: simulatedPhotoUrl,
          timestamp: new Date().toISOString(),
          status: "Verified"
        })
      });

      setSuccessAlert("Matrix database state updated and synchronized successfully.");
      
    } catch (error) {
      console.error("Firestore Registry Exception:", error);
      setErrorAlert(`Database Write Error: ${error.message}`);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0F172A] text-slate-100 p-6 flex flex-col items-center justify-center font-sans">
      <div className="w-full max-w-md bg-[#1E293B] border border-slate-700/60 rounded-xl shadow-2xl p-6">
        
        {/* Header Block */}
        <div className="mb-6 text-center">
          <h2 className="text-xl font-bold tracking-tight text-white">Material Worker Node</h2>
          <p className="text-xs text-slate-400 mt-1">GRWMS Matrix Inventory Audit Subsystem</p>
        </div>

        {/* Dynamic System Error / Success Alerts */}
        {errorAlert && (
          <div className="mb-4 p-3 bg-red-950/40 border border-red-800 text-red-200 rounded-lg flex items-start gap-2.5 text-xs">
            <AlertTriangle className="w-4 h-4 text-red-400 shrink-0 mt-0.5" />
            <span>{errorAlert}</span>
          </div>
        )}

        {successAlert && (
          <div className="mb-4 p-3 bg-emerald-950/40 border border-emerald-800 text-emerald-200 rounded-lg flex items-start gap-2.5 text-xs">
            <CheckCircle2 className="w-4 h-4 text-emerald-400 shrink-0 mt-0.5" />
            <span>{successAlert}</span>
          </div>
        )}

        <form onSubmit={handleProcessMatrixAudit} className="space-y-5">
          
          {/* Node Context Reference Field */}
          <div>
            <label className="block text-[11px] font-semibold tracking-wider uppercase text-slate-400 mb-1.5">
              Active Parent Station Registry Key
            </label>
            <input 
              type="text"
              value={parentId}
              onChange={(e) => setParentId(e.target.value)}
              className="w-full px-3 py-2 bg-[#0F172A] border border-slate-700 rounded-lg text-sm text-slate-200 focus:outline-none focus:border-blue-500 transition-colors"
              placeholder="e.g. platform no 1"
            />
          </div>

          {/* Shift Mass/Weight Input */}
          <div>
            <label className="block text-[11px] font-semibold tracking-wider uppercase text-slate-400 mb-1.5">
              Material Quantity / Unit Shift Weight
            </label>
            <input 
              type="number"
              min="1"
              value={quantity}
              onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
              className="w-full px-3 py-2 bg-[#0F172A] border border-slate-700 rounded-lg text-sm text-slate-200 focus:outline-none focus:border-blue-500 transition-colors"
            />
          </div>

          {/* Camera Frame Verification Block */}
          <div>
            <label className="block text-[11px] font-semibold tracking-wider uppercase text-slate-400 mb-1.5">
              State Audit Photo Block Verification
            </label>
            
            <div className="relative w-full aspect-video bg-[#0F172A] border border-slate-700 rounded-lg overflow-hidden flex items-center justify-center group">
              {previewUrl ? (
                /* Snapshot Image View Mode */
                <img 
                  src={previewUrl} 
                  alt="Audit verification asset" 
                  className="w-full h-full object-cover"
                />
              ) : (
                /* Live Streaming Video Stream Mode */
                <video
                  ref={videoRef}
                  className={`w-full h-full object-cover ${!cameraActive ? 'hidden' : 'block'}`}
                  playsInline
                  muted
                />
              )}

              {/* Hardware Connection Backup UI Indicator */}
              {!cameraActive && !previewUrl && (
                <div className="text-center p-4">
                  <Camera className="w-8 h-8 text-slate-600 mx-auto mb-2 animate-pulse" />
                  <p className="text-xs text-slate-500">Initializing media devices loop...</p>
                </div>
              )}
            </div>

            {/* Verification Hardware Control Actions */}
            <div className="mt-2.5">
              {previewUrl ? (
                <button
                  type="button"
                  onClick={handleRetake}
                  className="w-full py-1.5 px-3 bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-600 text-xs font-medium rounded-md transition-colors flex items-center justify-center gap-1.5"
                >
                  <RefreshCw className="w-3.5 h-3.5" />
                  Retake Payload Asset Frame
                </button>
              ) : (
                <button
                  type="button"
                  onClick={captureFrame}
                  disabled={!cameraActive}
                  className="w-full py-1.5 px-3 bg-blue-600 hover:bg-blue-500 disabled:bg-slate-800 disabled:text-slate-600 disabled:border-transparent text-white text-xs font-medium rounded-md transition-colors flex items-center justify-center gap-1.5"
                >
                  <Camera className="w-3.5 h-3.5" />
                  Capture Verification Frame
                </button>
              )}
            </div>
          </div>

          {/* Form Processing Submit Ingestion Engine Button */}
          <button
            type="submit"
            disabled={isProcessing}
            className="w-full mt-2 py-2.5 px-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white text-xs font-semibold uppercase tracking-wider rounded-lg shadow-md disabled:opacity-50 transition-all flex items-center justify-center gap-2"
          >
            {isProcessing ? (
              <>
                <RefreshCw className="w-3.5 h-3.5 animate-spin" />
                Processing Matrix Audit Changes...
              </>
            ) : (
              "Commit Ingestion Sequence"
            )}
          </button>

        </form>
      </div>
    </div>
  );
}
